class Solution:
    def clumsy(self, n: int) -> int:
        res, op = 1, 1
        for i in range(n, 1, -1):
            if op == 1:
                res *= i
            elif op == 2:
                res //= i
            elif op == 3:
                res += i
            else:
                res -= i
            op = (op + 1) % 4
        return res
